class Solution {
    public int reachNumber(int target) {
        target = Math.abs(target);
        int k = 0;
        int sum = 0;
        while (sum < target) {
            k++;
            sum += k;
        }
        int diff = sum - target;
        if (diff % 2 == 0) {
            return k;
        } else {
            if ((k + 1) % 2 == 1) {
                return k + 1;
            } else {
                return k + 2;
            }
        }
    }
}

